package core.org.apache.calcite.sql.util;

public class ChainedSqlOperatorTable implements SqlOperatorTable { protected final List < SqlOperatorTable > tableList ; public ChainedSqlOperatorTable ( List < SqlOperatorTable > tableList ) { this . tableList = ImmutableList . copyOf ( tableList ) ; } public static SqlOperatorTable of ( SqlOperatorTable ... tables ) { return new ChainedSqlOperatorTable ( ImmutableList . copyOf ( tables ) ) ; } public void add ( SqlOperatorTable table ) { if ( ! tableList . contains ( table ) ) { tableList . add ( table ) ; } } public void lookupOperatorOverloads ( SqlIdentifier opName , SqlFunctionCategory category , SqlSyntax syntax , List < SqlOperator > operatorList , SqlNameMatcher nameMatcher ) { for ( SqlOperatorTable table : tableList ) { table . lookupOperatorOverloads ( opName , category , syntax , operatorList , nameMatcher ) ; } } public List < SqlOperator > getOperatorList ( ) { List < SqlOperator > list = new ArrayList < > ( ) ; for ( SqlOperatorTable table : tableList ) { list . addAll ( table . getOperatorList ( ) ) ; } return list ; } }